patch:
diff --git a/llvm/lib/Transforms/Vectorize/VPlan.cpp b/llvm/lib/Transforms/Vectorize/VPlan.cpp
index e804f81c36db..bcaee051a01f 100644
--- a/llvm/lib/Transforms/Vectorize/VPlan.cpp
+++ b/llvm/lib/Transforms/Vectorize/VPlan.cpp
@@ -233,8 +233,14 @@ Value *VPTransformState::get(VPValue *Def, const VPLane &Lane) {
     return Data.VPV2Scalars[Def][0];
   }

+  if (!hasVectorValue(Def)) {
+    auto It = Data.VPV2Scalars.find(Def);
+    if (It != Data.VPV2Scalars.end() && !It->second.empty() && It->second[0])
+      return It->second[0];
+  }
   assert(hasVectorValue(Def));
   auto *VecPart = Data.VPV2Vector[Def];
+  assert(hasVectorValue(Def));
   if (!VecPart->getType()->isVectorTy()) {
     assert(Lane.isFirstLane() && "cannot get lane > 0 for scalar");
     return VecPart;

